import React, { useState } from "react";
import "./styles/App.css";
import BillingScreen from "./components/BillingScreen";
import FoodMenu from "./components/FoodMenu";
import RecentBills from "./components/RecentBills";
import AdminDashboard from "./components/AdminDashboard";
import ShiftManagement from "./components/ShiftManagement";

function LoginPanel({ onLogin }) {
  const [credential, setCredential] = useState("");
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);

  const submit = () => {
    const mode = credential.toLowerCase().includes("admin") ? "admin" : "clerk";
    onLogin(mode, date);
  };

  return (
    <div className="login-panel">
      <h2>Staff Login</h2>

      <div className="form-group">
        <label>Credential</label>
        <input
          type="text"
          value={credential}
          onChange={(e) => setCredential(e.target.value)}
          placeholder="Enter staff credentials"
        />
      </div>

      <div className="form-group">
        <label>Date</label>
        <input
          type="date"
          value={date}
          onChange={(e) => setDate(e.target.value)}
        />
      </div>

      <button
        onClick={submit}
        className="login-button"
        disabled={!(credential && date)}
      >
        Login
      </button>
    </div>
  );
}

export default function App() {
  const [mode, setMode] = useState("none");
  const [billingDate, setBillingDate] = useState(
    new Date().toISOString().split("T")[0]
  );
  const [activeTab, setActiveTab] = useState("billing");

  const handleLogin = (newMode, date) => {
    setMode(newMode || "clerk");
    setBillingDate(date || billingDate);
    setActiveTab("billing");
  };

  const handleLogout = () => {
    setMode("none");
    setActiveTab("login");
  };

  if (mode === "none") {
    return <LoginPanel onLogin={handleLogin} />;
  }

  const isAdmin = mode && mode.includes("admin");

  return (
    <div className="app">
      <div className="app-header">
        <nav className="nav-tabs">
          <button
            className={activeTab === "billing" ? "active" : ""}
            onClick={() => setActiveTab("billing")}
          >
            Billing
          </button>
          <button
            className={activeTab === "menu" ? "active" : ""}
            onClick={() => setActiveTab("menu")}
          >
            Menu
          </button>
          <button
            className={activeTab === "bills" ? "active" : ""}
            onClick={() => setActiveTab("bills")}
          >
            Recent Bills
          </button>
          {isAdmin && (
            <>
              <button
                className={activeTab === "admin" ? "active" : ""}
                onClick={() => setActiveTab("admin")}
              >
                Admin
              </button>
              <button
                className={activeTab === "shifts" ? "active" : ""}
                onClick={() => setActiveTab("shifts")}
              >
                Shifts
              </button>
            </>
          )}
        </nav>

        <div className="user-info">
          <span>Mode: {mode}</span>
          <span>Date: {billingDate}</span>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className="app-content">
        {activeTab === "billing" && (
          <BillingScreen billingDate={billingDate} userMode={mode} />
        )}
        {activeTab === "menu" && <FoodMenu />}
        {activeTab === "bills" && <RecentBills billingDate={billingDate} />}
        {activeTab === "admin" && isAdmin && (
          <AdminDashboard billingDate={billingDate} />
        )}
        {activeTab === "shifts" && isAdmin && (
          <ShiftManagement billingDate={billingDate} />
        )}
      </div>
    </div>
  );
}
